import inspect
import types
import math
def task_func(f):

    func_name = f.__name__
    signature = inspect.signature(f)
    num_args = len(signature.parameters)
    sqrt_num_args = math.sqrt(num_args)

    lambda_count = 0
    for param in signature.parameters.values():
        if param.default is not inspect.Parameter.empty:
            if isinstance(param.default, types.LambdaType):
                lambda_count += 1

    return {
        "name": func_name,
        "sqrt_num_args": sqrt_num_args,
        "lambda_count": lambda_count
    }

import re
import json
import os
def task_func(file_path: str, regex_pattern=r'\(.+?\)|\w') -> dict:
    results = {}
    try:
        with open(file_path, 'r') as f:
            data = json.load(f)
            json_string = json.dumps(data)
            matches = re.findall(regex_pattern, json_string)
            results[os.path.basename(file_path)] = matches
    except FileNotFoundError:
        print(f"Error: File not found at {file_path}")
    except json.JSONDecodeError:
        print(f"Error: Invalid JSON format in {file_path}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    return results

