import os
import shutil
import datetime
BACKUP_DIR = '/tmp/backup'
def get_unique_backup_dir():
    timestamp = datetime.datetime.now().strftime("%Y%m%d%H%M%S")
    return os.path.join(BACKUP_DIR, f"backup_{timestamp}")
def task_func(directory):
    errors = []
    backup_dir = get_unique_backup_dir()

    try:
        os.makedirs(backup_dir, exist_ok=True)

        shutil.copytree(directory, backup_dir, dirs_exist_ok=True)

        for item in os.listdir(directory):
            item_path = os.path.join(directory, item)
            try:
                if os.path.isfile(item_path) or os.path.islink(item_path):
                    os.unlink(item_path)
                elif os.path.isdir(item_path):
                    shutil.rmtree(item_path)
            except Exception as e:
                errors.append(f"Error cleaning {item_path}: {e}")

    except Exception as e:
        errors.append(f"Error during backup or cleaning: {e}")
        return None, errors

    return backup_dir, errors

